using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver — resolves any public type.
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1) GetTypeInfo<T>() — returns a strongly-typed JsonTypeInfo<T> directly.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> returned type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 38), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) TryGetTypeInfo<T>() — probe without throwing.
//    With the default resolver every public type resolves, so Person succeeds:
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded: {found!.Type.Name}");
else
    Console.WriteLine("TryGetTypeInfo<Person> returned false");

// Now demonstrate the "not available" path.
// Use a custom resolver that only knows about Person — Widget is unknown.
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver
    {
        Modifiers =
        {
            ti =>
            {
                if (ti.Type != typeof(Person))
                    throw new NotSupportedException($"Type {ti.Type.Name} is not supported");
            }
        }
    }
};

if (limited.TryGetTypeInfo<Widget>(out JsonTypeInfo<Widget>? widgetInfo))
    Console.WriteLine($"TryGetTypeInfo<Widget> succeeded: {widgetInfo!.Type.Name}");
else
    Console.WriteLine("TryGetTypeInfo<Widget> returned false — no exception thrown");

public record Person(string Name, int Age);
public record Widget(int Id, string Label);

